<?php namespace App\Repositories\Academic;use App\Repositories\BaseRepository;use App\Models\Academic\ClassSubject;use Illuminate\Database\Eloquent\Collection;class ClassSubjectRepository extends BaseRepository{    public function __construct(ClassSubject $model)    {        $this->model = $model;        parent::__construct($model);    }    public function findByClass(int $classId): Collection    {        return $this->findByField('class_id', $classId);    }    public function findBySubject(int $subjectId): Collection    {        return $this->findByField('subject_id', $subjectId);    }    public function findByClassAndSubject(int $classId, int $subjectId): ?ClassSubject    {        return $this->query()->where('class_id', $classId)->where('subject_id', $subjectId)->first();    }    public function getByAcademicYear(int $academicYearId): Collection    {        return $this->findByField('academic_year_id', $academicYearId);    }    public function getByType(string $type): Collection    {        return $this->findByField('type', $type);    }    public function getMandatorySubjects(int $classId): Collection    {        return $this->query()->where('class_id', $classId)->where('is_mandatory', true)->get();    }    public function getElectiveSubjects(int $classId): Collection    {        return $this->query()->where('class_id', $classId)->where('is_mandatory', false)->get();    }    public function assignSubjectToClass(int $classId, int $subjectId, array $data = []): ClassSubject    {        $data['class_id'] = $classId;        $data['subject_id'] = $subjectId;        return $this->create($data);    }    public function bulkAssign(int $classId, array $subjectIds): Collection    {        $assigned = collect();        foreach ($subjectIds as $subjectId) {            $existing = $this->findByClassAndSubject($classId, $subjectId);            if (!$existing) {                $assigned->push($this->assignSubjectToClass($classId, $subjectId));            }        }        return $assigned;    }}